using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;

var builder = Host.CreateApplicationBuilder(args);

// Register HttpClient for the tool class via DI
builder.Services.AddHttpClient<WeatherTools>(client =>
{
    client.BaseAddress = new Uri("https://api.open-meteo.com/");
});

// AddMcpServer registers the MCP pipeline; UseStdio wires stdin/stdout transport
builder.Services
    .AddMcpServer()
    .WithStdioServerTransport()
    .WithToolsFromAssembly();   // auto-discovers all [McpServerToolType] classes

await builder.Build().RunAsync();

using ModelContextProtocol.Server;
using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json.Serialization;

// The attribute marks this class for auto-discovery by WithToolsFromAssembly().
// The MCP host creates an instance per tool invocation, resolving constructor
// dependencies from the DI container (here: HttpClient via AddHttpClient<T>).
[McpServerToolType]
public class WeatherTools
{
    private readonly HttpClient _http;

    public WeatherTools(HttpClient http)
    {
        _http = http;
    }

    // [McpServerTool]  — exposes the method as a callable MCP tool.
    // [Description]    — becomes the tool description the LLM sees.
    // Parameter-level [Description] attributes become parameter descriptions.
    [McpServerTool, Description("Get current weather for a location.")]
    public async Task<string> GetCurrentWeather(
        [Description("Latitude of the location")]  double latitude,
        [Description("Longitude of the location")] double longitude)
    {
        var url = $"v1/forecast?latitude={latitude}&longitude={longitude}"
                + "&current=temperature_2m,wind_speed_10m";

        var result = await _http.GetFromJsonAsync<WeatherResponse>(url);

        return result is null
            ? "No data returned."
            : $"Temperature: {result.Current.Temperature}°C, "
            + $"Wind: {result.Current.WindSpeed} km/h";
    }
}

// DTOs — only used internally
public sealed class WeatherResponse
{
    [JsonPropertyName("current")]
    public CurrentWeather Current { get; set; } = new();
}

public sealed class CurrentWeather
{
    [JsonPropertyName("temperature_2m")]
    public double Temperature { get; set; }

    [JsonPropertyName("wind_speed_10m")]
    public double WindSpeed { get; set; }
}

